mapper.select:
SELECT p.*, p.PMT_DD DD, c.NAME CTG
FROM PAY p
LEFT JOIN CTG c ON c.ID = p.CTG_ID
WHERE p.USER_ID = #{id}

    AND MONTH(p.PMT_DD) = #{month}
    AND MONTH(p.PMT_DD) = MONTH(CURRENT_DATE)


    AND YEAR(p.PMT_DD) = #{year}
    AND YEAR(p.PMT_DD) = YEAR(CURRENT_DATE)


    AND p.CTG_ID = #{category}

ORDER BY p.PMT_DD DESC, p.ID DESC

SELECT IFNULL(SUM(AMT), 0)
FROM PAY
WHERE USER_ID = #{id}

    AND MONTH(PMT_DD) = #{month}
    AND MONTH(PMT_DD) = MONTH(CURRENT_DATE)


    AND YEAR(PMT_DD) = #{year}
    AND YEAR(PMT_DD) = YEAR(CURRENT_DATE)

SELECT IFNULL(SUM(AMT), 0)
FROM PAY
WHERE USER_ID = #{id}
  AND IS_PAID = false

    AND MONTH(PMT_DD) = #{month}
    AND MONTH(PMT_DD) = MONTH(CURRENT_DATE)


    AND YEAR(PMT_DD) = #{year}
    AND YEAR(PMT_DD) = YEAR(CURRENT_DATE)

SELECT IFNULL(SUM(AMT), 0)
FROM PAY
WHERE USER_ID = #{id}
AND CTG_ID = #{category}

    AND MONTH(PMT_DD) = #{month}
    AND MONTH(PMT_DD) = MONTH(CURRENT_DATE)


    AND YEAR(PMT_DD) = #{year}
    AND YEAR(PMT_DD) = YEAR(CURRENT_DATE)

mapper.insert:
INSERT INTO PAY ( NAME, AMT, CTG_ID, USER_ID, PMT_DD, IS_PAID ) VALUES ( #{name}, #{amt}, #{ctgId}, #{userId}, #{dd},
true false
)

mapper.update:
UPDATE PAY SET NAME = #{name}, AMT = #{amt}, CTG_ID = #{ctgId}, PMT_DD = #{dd},
IS_PAID = true, IS_PAID = false,
MOD_DT = CURRENT_TIMESTAMP WHERE ID = #{id} AND USER_ID = #{userId}

mapper.delete:
DELETE FROM PAY
WHERE ID = #{id}
  AND USER_ID = #{userId}
